package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.MfaBackupCode;
import com.example.mfa.repo.AppUserRepository;
import com.example.mfa.repo.MfaBackupCodeRepository;
import jakarta.transaction.Transactional;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Service
public class MfaBackupCodeService {
    private final AppUserRepository userRepository;
    private final MfaBackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public MfaBackupCodeService(AppUserRepository userRepository,
                               MfaBackupCodeRepository backupCodeRepository,
                               PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public BackupCodesResponse enableMfaAndGenerateBackupCodes(String username, int count) {
        if (count <= 0) count = 10;
        if (count > 50) count = 50;

        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        userRepository.save(user);

        backupCodeRepository.deleteAllByUserId(user.getId());

        List<String> plainCodes = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            String code = generateHumanCode();
            plainCodes.add(code);

            MfaBackupCode entity = new MfaBackupCode();
            entity.setUser(user);
            entity.setCodeHash(passwordEncoder.encode(code));
            entity.setUsed(false);
            entity.setCreatedAt(Instant.now());
            backupCodeRepository.save(entity);
        }

        return new BackupCodesResponse(user.getUsername(), user.isMfaEnabled(), plainCodes);
    }

    @Transactional
    public BackupCodesResponse regenerateBackupCodes(String username, int count) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA is not enabled");
        }

        backupCodeRepository.deleteAllByUserId(user.getId());

        List<String> plainCodes = new ArrayList<>(Math.min(Math.max(count, 1), 50));
        int n = plainCodes.capacity();
        for (int i = 0; i < n; i++) {
            String code = generateHumanCode();
            plainCodes.add(code);

            MfaBackupCode entity = new MfaBackupCode();
            entity.setUser(user);
            entity.setCodeHash(passwordEncoder.encode(code));
            entity.setUsed(false);
            entity.setCreatedAt(Instant.now());
            backupCodeRepository.save(entity);
        }

        return new BackupCodesResponse(user.getUsername(), user.isMfaEnabled(), plainCodes);
    }

    @Transactional
    public AuthResult authenticateWithBackupCode(String username, String backupCode) {
        if (backupCode == null || backupCode.isBlank()) {
            return new AuthResult(false, "Backup code required");
        }

        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!user.isMfaEnabled()) {
            return new AuthResult(false, "MFA not enabled");
        }

        String normalized = normalizeCode(backupCode);

        List<MfaBackupCode> candidates = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        for (MfaBackupCode c : candidates) {
            if (passwordEncoder.matches(normalized, c.getCodeHash())) {
                backupCodeRepository.markUsed(c.getId(), Instant.now());
                return new AuthResult(true, "Authenticated with backup code");
            }
        }

        return new AuthResult(false, "Invalid or already used backup code");
    }

    private String generateHumanCode() {
        byte[] bytes = new byte[9];
        secureRandom.nextBytes(bytes);
        String b64 = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        String raw = b64.replace("-", "").replace("_", "").toUpperCase();
        if (raw.length() < 10) {
            raw = raw + "ABCDEFGHJKMNPQRSTUVWXYZ23456789";
        }
        raw = raw.substring(0, 10);
        return raw.substring(0, 5) + "-" + raw.substring(5);
    }

    private String normalizeCode(String code) {
        return code.trim().replace(" ", "").replace("-", "").toUpperCase().substring(0, Math.min(10, code.trim().replace(" ", "").replace("-", "").toUpperCase().length()))
                .replaceAll("(.{5})(.{5})", "$1-$2");
    }
}

