package com.example.mfa.web;

import com.example.mfa.service.AuthResult;
import com.example.mfa.service.BackupCodesResponse;
import com.example.mfa.service.MfaBackupCodeService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaBackupCodeService mfaBackupCodeService;

    public MfaController(MfaBackupCodeService mfaBackupCodeService) {
        this.mfaBackupCodeService = mfaBackupCodeService;
    }

    @PostMapping("/enable")
    public ResponseEntity<BackupCodesResponse> enable(@RequestBody EnableMfaRequest request) {
        return ResponseEntity.ok(mfaBackupCodeService.enableMfaAndGenerateBackupCodes(request.getUsername(), request.getCount()));
    }

    @PostMapping("/recovery-codes/regenerate")
    public ResponseEntity<BackupCodesResponse> regenerate(@RequestBody EnableMfaRequest request) {
        return ResponseEntity.ok(mfaBackupCodeService.regenerateBackupCodes(request.getUsername(), request.getCount()));
    }

    @PostMapping("/authenticate/backup-code")
    public ResponseEntity<AuthResult> authWithBackupCode(@RequestBody BackupCodeAuthRequest request) {
        return ResponseEntity.ok(mfaBackupCodeService.authenticateWithBackupCode(request.getUsername(), request.getBackupCode()));
    }
}

package com.example.mfa.web;

import com.example.mfa.domain.AppUser;
import com.example.mfa.repo.AppUserRepository;
import org.springframework.http.ResponseEntity;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.web.bind.annotation.*;

import java.util.Optional;

@RestController
@RequestMapping("/api/users")
public class UserController {
    private final AppUserRepository userRepository;
    private final PasswordEncoder passwordEncoder;

    public UserController(AppUserRepository userRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public static class CreateUserRequest {
        private String username;
        private String password;

        public String getUsername() { return username; }
        public void setUsername(String username) { this.username = username; }

        public String getPassword() { return password; }
        public void setPassword(String password) { this.password = password; }
    }

    @PostMapping
    public ResponseEntity<?> create(@RequestBody CreateUserRequest req) {
        if (req.getUsername() == null || req.getUsername().isBlank()) return ResponseEntity.badRequest().body("username required");
        if (req.getPassword() == null || req.getPassword().isBlank()) return ResponseEntity.badRequest().body("password required");

        Optional<AppUser> existing = userRepository.findByUsername(req.getUsername());
        if (existing.isPresent()) return ResponseEntity.status(409).body("username already exists");

        AppUser u = new AppUser();
        u.setUsername(req.getUsername());
        u.setPasswordHash(passwordEncoder.encode(req.getPassword()));
        u.setMfaEnabled(false);
        userRepository.save(u);

        return ResponseEntity.ok(u.getId());
    }
}

