@Configuration
class SeedData {
    @Bean
    CommandLineRunner seed(AppUserRepository userRepository, PasswordEncoder encoder) {
        return args -> {
            if (userRepository.findByUsername("alice").isEmpty()) {
                AppUser u = new AppUser();
                u.setUsername("alice");
                u.setPasswordHash(encoder.encode("password"));
                u.setMfaEnabled(false);
                userRepository.save(u);
            }
        };
    }
}

package com.example.mfa.web;

import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestControllerAdvice
public class GlobalExceptionHandler {
    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<String> badRequest(IllegalArgumentException ex) {
        return ResponseEntity.badRequest().body(ex.getMessage());
    }

    @ExceptionHandler(IllegalStateException.class)
    public ResponseEntity<String> conflict(IllegalStateException ex) {
        return ResponseEntity.status(409).body(ex.getMessage());
    }

    @ExceptionHandler(DataIntegrityViolationException.class)
    public ResponseEntity<String> dataIntegrity(DataIntegrityViolationException ex) {
        return ResponseEntity.status(409).body("Data integrity violation");
    }
}

